                "name": "Besant Lodge",
                "description": "A historic 1920s meeting hall for the Theosophical Society, a cornerstone of Beachwood's spiritualist history.",
                "type": "landmark",
                "address": "2560 N Beachwood Dr, Los Angeles, CA 90068",
                "lat": 34.1171666,
                "lng": -118.3214273,
